class Solution:
    def maxGCDScore(self, nums: List[int], k: int) -> int:
        n = len(nums)
        dp = [[0] * (k + 1) for _ in range(n + 1)]
        for i in range(1, n + 1):
            for j in range(1, min(i, k) + 1):
                for x in range(i):
                    dp[i][j] = max(dp[i][j], dp[x][j - 1] * gcd(nums[x], nums[i]) * (i - x))
        return max(dp[n])
```

